// The SEN66 sends physical values as floats (ALREADY_SCALED = true).
// If your firmware sends raw Sensirion integers, set ALREADY_SCALED = false
// and the scale factors below will be applied:
//   PM:          ÷ 10  → µg/m³
//   Humidity:    ÷ 100 → %RH
//   Temperature: ÷ 200 → °C
//   VOC/NOx:     ÷ 10  → Index
//   CO2:         no scaling (already in ppm)
const ALREADY_SCALED = true;

const d = msg.payload;

let fields;
if (ALREADY_SCALED) {
    fields = {
        pm1_0:       parseFloat(d.pm1_0)       || 0,
        pm2_5:       parseFloat(d.pm2_5)       || 0,
        pm4_0:       parseFloat(d.pm4_0)       || 0,
        pm10_0:      parseFloat(d.pm10_0)      || 0,
        humidity:    parseFloat(d.humidity)    || 0,
        temperature: parseFloat(d.temperature) || 0,
        voc_index:   parseFloat(d.voc_index)   || 0,
        nox_index:   parseFloat(d.nox_index)   || 0,
        co2:         parseFloat(d.co2)         || 0
    };
} else {
    fields = {
        pm1_0:       (d.pm1_0       || 0) / 10,
        pm2_5:       (d.pm2_5       || 0) / 10,
        pm4_0:       (d.pm4_0       || 0) / 10,
        pm10_0:      (d.pm10_0      || 0) / 10,
        humidity:    (d.humidity    || 0) / 100,
        temperature: (d.temperature || 0) / 200,
        voc_index:   (d.voc_index   || 0) / 10,
        nox_index:   (d.nox_index   || 0) / 10,
        co2:          d.co2          || 0
    };
}

// InfluxDB line-protocol payload for node-red-contrib-influxdb
msg.payload = [
    {
        measurement: "sen66",
        tags: {
            // Add sensor location/ID tags here if you have multiple sensors.
            // sensor_id: "sensor-01"
        },
        fields: fields
        // timestamp is omitted → InfluxDB uses server time (recommended)
    }
];

return msg;
